import itertools, numpy as np, math
# define numeric epsilon .1
e=0.1
verts={'A0':np.array([0.,0.,0.]),'A1':np.array([1.,0.,0.]),'A2':np.array([0.,1.,0.]),
       'B0':np.array([0.5,0.,e]),'B1':np.array([0.5-e,0.5,-2*e]),'B2':np.array([e,0.5,0.])}
face_names=[('A0','B0','A2'),('B0','A1','A2'),('A1','B1','A0'),('B1','A2','A0'),('A2','B2','A1'),('B2','A0','A1')]
def normal(face):
    P,Q,R=[verts[v] for v in face]
    return np.cross(Q-P,R-P)
norms=[normal(f) for f in face_names]
